def process(list, fieldName, fieldValue):
    """Filter list to only structs/dicts where field matches value"""
    if not list or not isinstance(list, (list, tuple)):
        return [], 0
    field = str(fieldName or '')
    result = []
    for item in list:
        if isinstance(item, dict) and field in item:
            if item[field] == fieldValue:
                result.append(item)
    return result, len(result)
